const items = $input.all();
const results = [];
const trigger = $('Webhook Trigger').first().json;
const first = $('HTTP Request1').first().json;

function toInt(v) {
  if (typeof v === 'number') return v;
  if (typeof v === 'string') return parseInt(v.replace(/[^0-9-]/g, ''), 10) || 0;
  return 0;
}

// Discard unresolved template literals like {{input.client_name}}
function clean(v) {
  if (!v || typeof v !== 'string') return '';
  if (v.startsWith('{{') || v.startsWith('$json') || v.startsWith("$('")) return '';
  return v;
}

const clientName = clean(trigger.client_name) || clean(first.client_name) || '';
const ownInstagram = clean(trigger.own_instagram) || clean(first.own_instagram) || '';

for (const item of items) {
  const loopItem = item.json;
  if (loopItem.isPinned) continue;

  // Parse analysis: may be string from LLM Chain
  let analysis = loopItem.analysis || null;
  if (typeof analysis === 'string') {
    try { analysis = JSON.parse(analysis); } catch { analysis = null; }
  }

  results.push({
    json: {
      id: loopItem.id,
      post_url: loopItem.url || loopItem.postUrl,
      thumbnail_url: loopItem.displayUrl || loopItem.thumbnailUrl || null,
      caption: loopItem.caption || '',
      media_type: loopItem.type || 'video',
      profile_id: trigger.profile_id || first.profile_id,
      client_name: clientName,
      own_instagram: ownInstagram,
      analysis: analysis,
      curtidas: toInt(loopItem.likesCount),
      visualizacoes: toInt(loopItem.videoViewCount),
      envios: 0
    }
  });
}

return results;
